import React from 'react';
import type { Lesson, CourseModule } from '../types';

interface LessonViewProps {
  lesson: Lesson;
  onMarkComplete: (lessonId: string) => void;
  allModules: CourseModule[];
  onSelectLesson: (lesson: Lesson) => void;
}

export const LessonView: React.FC<LessonViewProps> = ({ lesson, onMarkComplete, allModules, onSelectLesson }) => {

  const renderContent = (content: string) => {
    return content.split('\n\n').map((paragraph, index) => {
      if (paragraph.startsWith('```')) {
        const code = paragraph.replace(/```(javascript|python)?\n|```/g, '');
        return (
          <pre key={index} className="bg-slate-900 rounded-lg p-4 my-4 overflow-x-auto">
            <code className="text-sm text-white">{code}</code>
          </pre>
        );
      }
      return (
        <p key={index} className="mb-4 text-slate-300 leading-relaxed">
          {paragraph}
        </p>
      );
    });
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 lg:gap-12">
      {/* Sidebar */}
      <aside className="w-full lg:w-1/4 lg:flex-shrink-0">
        <div className="sticky top-24">
          <h3 className="text-xl font-bold text-white mb-4">Course Lessons</h3>
          <nav className="space-y-2">
            {allModules.map(module => (
              <div key={module.id}>
                <h4 className="font-semibold text-neon-teal mt-4 mb-2">{module.title}</h4>
                {module.lessons.map(l => (
                  <button
                    key={l.id}
                    onClick={() => onSelectLesson(l)}
                    className={`w-full text-left px-3 py-2 text-sm rounded-md transition-colors duration-200 ${
                      lesson.id === l.id
                        ? 'bg-neon-teal text-slate-900'
                        : 'text-slate-300 hover:bg-slate-700'
                    }`}
                  >
                    {l.title}
                  </button>
                ))}
              </div>
            ))}
          </nav>
        </div>
      </aside>

      {/* Main Content */}
      <article className="w-full lg:w-3/4 bg-slate-800 p-6 sm:p-10 rounded-xl border border-slate-700">
        <h1 className="text-3xl md:text-4xl font-bold text-white mb-6">{lesson.title}</h1>
        <div className="prose prose-invert max-w-none text-slate-300">
            {renderContent(lesson.content)}
        </div>
        <div className="mt-10 border-t border-slate-700 pt-6">
          <button
            onClick={() => onMarkComplete(lesson.id)}
            className="w-full md:w-auto bg-neon-teal text-slate-900 font-bold py-3 px-8 rounded-full text-lg hover:bg-neon-teal-dark transition-all duration-300 transform hover:scale-105"
          >
            Mark as Complete
          </button>
        </div>
      </article>
    </div>
  );
};

import React, { useState } from 'react';
import { quizQuestions } from '../constants';

export const Quiz: React.FC = () => {
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);
  const [score, setScore] = useState(0);
  const [quizFinished, setQuizFinished] = useState(false);

  const currentQuestion = quizQuestions[currentQuestionIndex];
  const isCorrect = selectedAnswer === currentQuestion.correctAnswerIndex;

  const handleAnswerSelect = (index: number) => {
    if (showFeedback) return;
    setSelectedAnswer(index);
    setShowFeedback(true);
    if (index === currentQuestion.correctAnswerIndex) {
      setScore(prev => prev + 1);
    }
  };

  const handleNextQuestion = () => {
    setShowFeedback(false);
    setSelectedAnswer(null);
    if (currentQuestionIndex < quizQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      setQuizFinished(true);
    }
  };

  const handleRestart = () => {
    setCurrentQuestionIndex(0);
    setSelectedAnswer(null);
    setShowFeedback(false);
    setScore(0);
    setQuizFinished(false);
  }

  if (quizFinished) {
    return (
      <div className="text-center bg-slate-800 p-8 rounded-xl max-w-2xl mx-auto">
        <h2 className="text-3xl font-bold text-white mb-4">Quiz Complete!</h2>
        <p className="text-xl text-neon-teal mb-6">Your Score: {score} / {quizQuestions.length}</p>
        <button 
          onClick={handleRestart}
          className="bg-neon-teal text-slate-900 font-bold py-2 px-6 rounded-full hover:bg-neon-teal-dark transition-colors duration-300"
        >
          Restart Quiz
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto">
      <h1 className="text-4xl font-bold text-center text-white mb-8">Test Your Knowledge</h1>
      <div className="bg-slate-800 p-8 rounded-xl border border-slate-700 shadow-lg">
        <p className="text-sm text-slate-400 mb-2">Question {currentQuestionIndex + 1} of {quizQuestions.length}</p>
        <h2 className="text-2xl font-semibold text-white mb-6">{currentQuestion.question}</h2>
        <div className="space-y-4">
          {currentQuestion.options.map((option, index) => {
            let buttonClass = 'bg-slate-700 hover:bg-slate-600';
            if (showFeedback) {
              if (index === currentQuestion.correctAnswerIndex) {
                buttonClass = 'bg-green-500/50 border-green-500';
              } else if (index === selectedAnswer) {
                buttonClass = 'bg-red-500/50 border-red-500';
              }
            }
            return (
              <button
                key={index}
                onClick={() => handleAnswerSelect(index)}
                disabled={showFeedback}
                className={`w-full text-left p-4 rounded-lg border border-slate-600 transition-colors duration-200 text-white ${buttonClass} ${!showFeedback ? 'cursor-pointer' : 'cursor-default'}`}
              >
                {option}
              </button>
            );
          })}
        </div>

        {showFeedback && (
          <div className="mt-6 text-center">
            <p className={`text-lg font-bold ${isCorrect ? 'text-green-400' : 'text-red-400'}`}>
              {isCorrect ? 'Correct!' : 'Incorrect.'}
            </p>
            <button
              onClick={handleNextQuestion}
              className="mt-4 bg-neon-teal text-slate-900 font-bold py-2 px-6 rounded-full hover:bg-neon-teal-dark transition-colors duration-300"
            >
              {currentQuestionIndex < quizQuestions.length - 1 ? 'Next Question' : 'Finish Quiz'}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { glossaryTerms } from '../constants';

export const Glossary: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredTerms = useMemo(() => {
    if (!searchTerm) {
      return glossaryTerms;
    }
    return glossaryTerms.filter(term =>
      term.term.toLowerCase().includes(searchTerm.toLowerCase()) ||
      term.definition.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [searchTerm]);

  return (
    <div className="max-w-4xl mx-auto">
      <h1 className="text-4xl font-bold text-center text-white mb-4">AI Glossary</h1>
      <p className="text-lg text-slate-400 text-center mb-8">
        A searchable list of common terms and concepts in Artificial Intelligence.
      </p>

      <div className="relative mb-8">
        <input
          type="text"
          placeholder="Search for a term..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full p-4 pl-12 bg-slate-800 border border-slate-700 rounded-full text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-neon-teal"
        />
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6 absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
          <path strokeLinecap="round" strokeLinejoin="round" d="m21 21-5.197-5.197m0 0A7.5 7.5 0 1 0 5.196 5.196a7.5 7.5 0 0 0 10.607 10.607Z" />
        </svg>
      </div>

      <div className="space-y-4">
        {filteredTerms.length > 0 ? (
            filteredTerms.map(term => (
                <div key={term.term} className="bg-slate-800/50 p-6 rounded-lg border border-slate-700">
                <h3 className="text-xl font-bold text-neon-teal">{term.term}</h3>
                <p className="text-slate-300 mt-2">{term.definition}</p>
                </div>
            ))
        ) : (
            <div className="text-center p-8 bg-slate-800 rounded-lg">
                <p className="text-slate-400">No terms found for "{searchTerm}".</p>
            </div>
        )}
      </div>
    </div>
  );
};

