  if (quizFinished) {
    return (
      <div className="text-center bg-slate-800 p-8 rounded-xl max-w-2xl mx-auto">
        <h2 className="text-3xl font-bold text-white mb-4">Quiz Complete!</h2>
        <p className="text-xl text-neon-teal mb-6">Your Score: {score} / {quizQuestions.length}</p>
        <button 
          onClick={handleRestart}
          className="bg-neon-teal text-slate-900 font-bold py-2 px-6 rounded-full hover:bg-neon-teal-dark transition-colors duration-300"
        >
          Restart Quiz
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto">
      <h1 className="text-4xl font-bold text-center text-white mb-8">Test Your Knowledge</h1>
      <div className="bg-slate-800 p-8 rounded-xl border border-slate-700 shadow-lg">
