import React, { useState, useEffect } from 'react';
import type { Lesson, CourseModule } from '../types';

interface LessonViewProps {
  lesson: Lesson;
  onMarkComplete: (lessonId: string) => void;
  allModules: CourseModule[];
  onSelectLesson: (lesson: Lesson) => void;
}

export const LessonView: React.FC<LessonViewProps> = ({ lesson, onMarkComplete, allModules, onSelectLesson }) => {
  const findModuleIdForLesson = (lessonId: string): string | null => {
    for (const module of allModules) {
      if (module.lessons.some(l => l.id === lessonId)) {
        return module.id;
      }
    }
    return null;
  };

  const [openModules, setOpenModules] = useState<Set<string>>(() => {
    const activeModuleId = findModuleIdForLesson(lesson.id);
    return activeModuleId ? new Set([activeModuleId]) : new Set();
  });

  useEffect(() => {
    const activeModuleId = findModuleIdForLesson(lesson.id);
    if (activeModuleId && !openModules.has(activeModuleId)) {
      setOpenModules(prevOpen => {
        const newOpen = new Set(prevOpen);
        newOpen.add(activeModuleId);
        return newOpen;
      });
    }
  }, [lesson.id, allModules]);

  const toggleAccordion = (moduleId: string) => {
    setOpenModules(prevOpen => {
      const newOpen = new Set(prevOpen);
      if (newOpen.has(moduleId)) {
        newOpen.delete(moduleId);
      } else {
        newOpen.add(moduleId);
      }
      return newOpen;
    });
  };

  const renderContent = (content: string) => {
    return content.split('\n\n').map((paragraph, index) => {
      // Bold text support: **text**
      const parts = paragraph.split(/(\*\*.*?\*\*)/g).map((part, i) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={i}>{part.slice(2, -2)}</strong>;
        }
        return part;
      });

      // List support: - item
      if (paragraph.trim().startsWith('- ')) {
         return (
             <ul key={index} className="list-disc list-inside mb-4">
                 {paragraph.split('\n').map((item, itemIndex) => (
                     <li key={itemIndex} className="mb-1">{item.replace(/- /,'')}</li>
                 ))}
             </ul>
         );
      }

      if (paragraph.startsWith('```')) {
        const code = paragraph.replace(/```(javascript|python)?\n|```/g, '');
        return (
          <pre key={index} className="bg-brand-black rounded-lg p-4 my-4 overflow-x-auto">
            <code className="text-sm text-white">{code}</code>
          </pre>
        );
      }
      return (
        <p key={index} className="mb-4 text-brand-light-gray leading-relaxed">
          {parts}
        </p>
      );
    });
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 lg:gap-12">
      {/* Sidebar */}
      <aside className="w-full lg:w-1/4 lg:flex-shrink-0">
        <div className="sticky top-24">
          <h3 className="text-xl font-bold text-white mb-4">Course Lessons</h3>
          <nav className="space-y-1">
            {allModules.map(module => {
              const isOpen = openModules.has(module.id);
              return (
                <div key={module.id}>
                  <button
                    onClick={() => toggleAccordion(module.id)}
                    className="w-full flex justify-between items-center text-left p-3 rounded-md hover:bg-brand-gray-dark/50 focus:outline-none focus:ring-2 focus:ring-brand-green/50 transition-colors duration-200"
                    aria-expanded={isOpen}
                  >
                    <span className="font-semibold text-brand-green">{module.title}</span>
                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className={`w-5 h-5 text-brand-light-gray transform transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="m19.5 8.25-7.5 7.5-7.5-7.5" />
                    </svg>
                  </button>
                  {isOpen && (
                    <div className="pl-3 mt-1 space-y-1">
                      {module.lessons.map(l => (
                        <button
                          key={l.id}
                          onClick={() => onSelectLesson(l)}
                          className={`w-full text-left px-3 py-2 text-sm rounded-md transition-colors duration-200 ${
                            lesson.id === l.id
                              ? 'bg-brand-green text-brand-black font-medium'
                              : 'text-brand-light-gray hover:bg-brand-border'
                          }`}
                        >
                          {l.title}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              );
            })}
          </nav>
        </div>
      </aside>

      {/* Main Content */}
      <article className="w-full lg:w-3/4 bg-brand-gray-dark p-6 sm:p-10 rounded-xl border border-brand-border">
        <h1 className="text-3xl md:text-4xl font-bold text-white mb-6">{lesson.title}</h1>
        <div className="prose prose-invert max-w-none text-brand-light-gray">
            {renderContent(lesson.content)}
        </div>
        <div className="mt-10 border-t border-brand-border pt-6">
          <button
            onClick={() => onMarkComplete(lesson.id)}
            className="w-full md:w-auto bg-brand-green text-brand-black font-bold py-3 px-8 rounded-full text-lg hover:bg-brand-green-dark transition-all duration-300 transform hover:scale-105"
          >
            Mark as Complete
          </button>
        </div>
      </article>
    </div>
  );
};

import React, { useState } from 'react';
import { quizQuestions } from '../constants';

export const Quiz: React.FC = () => {
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);
  const [score, setScore] = useState(0);
  const [quizFinished, setQuizFinished] = useState(false);

  const currentQuestion = quizQuestions[currentQuestionIndex];
  const isCorrect = selectedAnswer === currentQuestion.correctAnswerIndex;

  const handleAnswerSelect = (index: number) => {
    if (showFeedback) return;
    setSelectedAnswer(index);
    setShowFeedback(true);
    if (index === currentQuestion.correctAnswerIndex) {
      setScore(prev => prev + 1);
    }
  };

  const handleNextQuestion = () => {
    setShowFeedback(false);
    setSelectedAnswer(null);
    if (currentQuestionIndex < quizQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      setQuizFinished(true);
    }
  };

  const handleRestart = () => {
    setCurrentQuestionIndex(0);
    setSelectedAnswer(null);
    setShowFeedback(false);
    setScore(0);
    setQuizFinished(false);
  }

  if (quizFinished) {
    return (
      <div className="text-center bg-brand-gray-dark p-8 rounded-xl max-w-2xl mx-auto">
        <h2 className="text-3xl font-bold text-white mb-4">Quiz Complete!</h2>
        <p className="text-xl text-brand-green mb-6">Your Score: {score} / {quizQuestions.length}</p>
        <button 
          onClick={handleRestart}
          className="bg-brand-green text-brand-black font-bold py-2 px-6 rounded-full hover:bg-brand-green-dark transition-colors duration-300"
        >
          Restart Quiz
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto">
      <h1 className="text-4xl font-bold text-center text-white mb-8">Test Your Knowledge</h1>
      <div className="bg-brand-gray-dark p-8 rounded-xl border border-brand-border shadow-lg">
        <p className="text-sm text-brand-light-gray mb-2">Question {currentQuestionIndex + 1} of {quizQuestions.length}</p>
        <h2 className="text-2xl font-semibold text-white mb-6">{currentQuestion.question}</h2>
        <div className="space-y-4">
          {currentQuestion.options.map((option, index) => {
            let buttonClass = 'bg-brand-gray-dark hover:bg-brand-border';
            if (showFeedback) {
              if (index === currentQuestion.correctAnswerIndex) {
                buttonClass = 'bg-brand-green/50 border-brand-green';
              } else if (index === selectedAnswer) {
                buttonClass = 'bg-brand-red/50 border-brand-red';
              }
            }
            return (
              <button
                key={index}
                onClick={() => handleAnswerSelect(index)}
                disabled={showFeedback}
                className={`w-full text-left p-4 rounded-lg border border-brand-border transition-colors duration-200 text-white ${buttonClass} ${!showFeedback ? 'cursor-pointer' : 'cursor-default'}`}
              >
                {option}
              </button>
            );
          })}
        </div>

        {showFeedback && (
          <div className="mt-6 text-center">
            <p className={`text-lg font-bold ${isCorrect ? 'text-brand-green' : 'text-brand-red'}`}>
              {isCorrect ? 'Correct!' : 'Incorrect.'}
            </p>
            <div className="mt-4 text-left bg-brand-black/50 p-4 rounded-lg border border-brand-border">
              <h4 className="font-bold text-white">Rationale:</h4>
              <p className="text-brand-light-gray">{currentQuestion.rationale}</p>
            </div>
            <button
              onClick={handleNextQuestion}
              className="mt-4 bg-brand-green text-brand-black font-bold py-2 px-6 rounded-full hover:bg-brand-green-dark transition-colors duration-300"
            >
              {currentQuestionIndex < quizQuestions.length - 1 ? 'Next Question' : 'Finish Quiz'}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { glossaryTerms } from '../constants';

export const Glossary: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredTerms = useMemo(() => {
    // Sort terms alphabetically before filtering
    const sortedTerms = [...glossaryTerms].sort((a, b) => a.term.localeCompare(b.term));
    if (!searchTerm) {
      return sortedTerms;
    }
    return sortedTerms.filter(term =>
      term.term.toLowerCase().includes(searchTerm.toLowerCase()) ||
      term.definition.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [searchTerm]);

  return (
    <div className="max-w-4xl mx-auto">
      <h1 className="text-4xl font-bold text-center text-white mb-4">AI Glossary</h1>
      <p className="text-lg text-brand-light-gray text-center mb-8">
        A searchable list of common terms and concepts in Artificial Intelligence.
      </p>

      <div className="relative mb-8">
        <input
          type="text"
          placeholder="Search for a term..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full p-4 pl-12 bg-brand-gray-dark border border-brand-border rounded-full text-white placeholder-brand-light-gray focus:outline-none focus:ring-2 focus:ring-brand-green"
        />
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6 absolute left-4 top-1/2 -translate-y-1/2 text-brand-light-gray">
          <path strokeLinecap="round" strokeLinejoin="round" d="m21 21-5.197-5.197m0 0A7.5 7.5 0 1 0 5.196 5.196a7.5 7.5 0 0 0 10.607 10.607Z" />
        </svg>
      </div>

      <div className="space-y-4">
        {filteredTerms.length > 0 ? (
            filteredTerms.map(term => (
                <div key={term.term} className="bg-brand-gray-dark/50 p-6 rounded-lg border border-brand-border">
                <h3 className="text-xl font-bold text-brand-green">{term.term}</h3>
                <p className="text-brand-light-gray mt-2">{term.definition}</p>
                </div>
            ))
        ) : (
            <div className="text-center p-8 bg-brand-gray-dark rounded-lg">
                <p className="text-brand-light-gray">No terms found for "{searchTerm}".</p>
            </div>
        )}
      </div>
    </div>
  );
};

